  return k+': '+bh.name+'\n  Status: '+(bh.status||'')+'\n  Scope: '+(bh.scope||'')+'\n  Win: '+(bh.win_condition||'')+'\n  Expands to: '+(bh.expands_to||'')+'\n  Key buyers: '+(bh.key_buyers||'')+'\n  Compliance hooks: '+(bh.compliance_hooks||'')+'\n  Pricing: '+(bh.pricing||'')+'\n  Grants: '+(bh.grant_sources||bh.grant_sources_on_activation||'');
}).join('\n\n');
const activeConstraints = Object.entries(stageConstraints).filter(function(e) { return e[1] === true; }).map(function(e) { return e[0]; });
const urgentDeadlines = deadlines.filter(function(d) { return ['OPPORTUNITY','PENDING','OVERDUE','IN PROGRESS'].includes(d.status); }).slice(0,8).map(function(d) { return d.item+' | Due: '+d.date+' | '+d.status+' | '+d.entity+(d.notes?' | '+d.notes:''); }).join('\n');
