  isScheduled: isScheduled, manualFocus: manualFocus, timestamp: new Date().toISOString(),
  founderName: founder.name||'Kevin Alexander Smith',
  founderCredentials: (founder.credentials||[]).join(', '),
  founderBackground: founder.background||'',
