  return new Promise(function(resolve) {
    const req = https.request({ hostname: 'api.anthropic.com', port: 443, path: '/v1/messages', method: 'POST', headers: { 'Content-Type': 'application/json', 'x-api-key': process.env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'Content-Length': Buffer.byteLength(rb) } }, function(res) {
      let d = ''; res.on('data', function(c) { d += c; });
      res.on('end', function() {
        try { const t = JSON.parse(d).content[0].text || '{}'; resolve(JSON.parse(t.replace(/^```json\s*/,'').replace(/^```\s*/,'').replace(/\s*```$/,'').trim())); }
        catch(e) { resolve({ _error: e.message }); }
      });
    });
    req.on('error', function() { resolve({ _error: 'request failed' }); });
    req.write(rb); req.end();
  });
}
