function fetchJson(hostname, path, method, body, ms) {
  return new Promise(function(resolve) {
    const timer = setTimeout(function() { resolve({ ok: false, error: 'timeout', data: null }); }, ms || 10000);
    try {
      const opts = { hostname: hostname, port: 443, path: path, method: method || 'GET', headers: { 'Content-Type': 'application/json', 'User-Agent': 'KAI-Netics-Nova/3.2', 'Accept': 'application/json' } };
      if (body) opts.headers['Content-Length'] = Buffer.byteLength(body);
      const req = https.request(opts, function(res) {
        let d = ''; res.on('data', function(c) { d += c; });
        res.on('end', function() {
          clearTimeout(timer);
          try { resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, data: JSON.parse(d) }); }
          catch(e) { resolve({ ok: false, error: 'parse('+res.statusCode+'): '+d.substring(0,150), data: null }); }
        });
      });
      req.on('error', function(e) { clearTimeout(timer); resolve({ ok: false, error: e.message, data: null }); });
      if (body) req.write(body); req.end();
    } catch(e) { clearTimeout(timer); resolve({ ok: false, error: e.message, data: null }); }
  });
}
